 * Sentence-aware text chunker for synthesis input.
 *
 * Splits arbitrary text into an array of chunks, each no longer than
 * `maxLength` characters.  The algorithm favours natural sentence boundaries
 * (`.`, `!`, `?`) — a new chunk is started only when appending the next
 * sentence would exceed the limit.  Sentences that are themselves longer than
 * `maxLength` are hard-split into `maxLength`-sized slices so no characters
 * are lost.
 *
 * The function is **pure**: it has no side effects, no imports, and no
 * module-level state.  It only understands the ASCII sentence terminators
 * `.`, `!`, and `?`; Unicode sentence boundaries are not handled.
 *
 * @param text      - The input string to chunk.
 * @param maxLength - Maximum length of each returned chunk (must be > 0).
 * @returns An array of chunks whose concatenation equals the trimmed input.
 * @throws {Error} If `maxLength` is not a positive number.
 */
export function chunkText(text: string, maxLength: number): string[] {
  if (maxLength <= 0) {
    throw new Error('maxLength must be a positive number');
  }

  const trimmed = text.trim();
  if (trimmed.length === 0) {
    return [];
  }

  if (trimmed.length <= maxLength) {
    return [trimmed];
  }

  // Split into sentence segments, keeping punctuation attached.
  // Pattern: non-punctuation chars followed by one or more sentence-ending
  // punctuation marks, OR the final run of non-punctuation chars at end.
  const matches = trimmed.match(/[^.!?]*[.!?]+|[^.!?]+$/g);
  const sentences: string[] = matches ?? [];

  const chunks: string[] = [];
  let current = '';

  for (const sentence of sentences) {
    if (sentence.length > maxLength) {
      // Flush any pending chunk before hard-splitting the long sentence.
      if (current.length > 0) {
        chunks.push(current);
        current = '';
      }

      // Hard-split: slice the over-long sentence into maxLength-sized pieces.
      for (let i = 0; i < sentence.length; i += maxLength) {
        chunks.push(sentence.slice(i, i + maxLength));
      }
    } else if (current.length + sentence.length <= maxLength) {
      // Fits in the current chunk — keep packing.
      current += sentence;
    } else {
      // Would overflow — start a new chunk.
      chunks.push(current);
      current = sentence;
    }
  }

  if (current.length > 0) {
    chunks.push(current);
  }

  return chunks;
}

