import { describe, it, expect } from 'vitest';
import { chunkText } from './chunk-text';

// ─── Edge cases: empty / whitespace / under-limit ───────────────────────────

describe('chunkText', () => {
  describe('empty and whitespace inputs', () => {
    it('returns [] for an empty string', () => {
      expect(chunkText('', 10)).toEqual([]);
    });

    it('returns [] for a whitespace-only string', () => {
      expect(chunkText('   ', 10)).toEqual([]);
    });

    it('returns [] for a string of newlines and tabs', () => {
      expect(chunkText('\n\t \r', 5)).toEqual([]);
    });
  });

  describe('under-limit and exactly-at-limit', () => {
    it('returns [text] when text is shorter than maxLength', () => {
      expect(chunkText('Hello', 10)).toEqual(['Hello']);
    });

    it('returns [text] when text length equals maxLength', () => {
      expect(chunkText('Hello', 5)).toEqual(['Hello']);
    });
  });

  // ─── Sentence-boundary packing ────────────────────────────────────────────

  describe('multi-sentence packing', () => {
    it('packs short sentences greedily into chunks', () => {
      // 'Hello.' (6) + ' World!' (7) = 13 > 10, so each is its own chunk
      const result = chunkText('Hello. World!', 10);
      expect(result).toEqual(['Hello.', ' World!']);
    });

    it('keeps two short sentences together when they fit', () => {
      // 'Hi.' (3) + ' Ok.' (4) = 7 <= 10
      const result = chunkText('Hi. Ok.', 10);
      expect(result).toEqual(['Hi. Ok.']);
    });

    it('packs three sentences with mixed fitting', () => {
      // 'A.' (2) + ' B.' (3) + ' C.' (3) = 8 <= 8, all fit
      const result = chunkText('A. B. C.', 8);
      expect(result).toEqual(['A. B. C.']);
    });

    it('starts a new chunk when the next sentence would overflow', () => {
      // 'First.' (6) + ' Second.' (8) = 14 > 10
      const result = chunkText('First. Second.', 10);
      expect(result).toEqual(['First.', ' Second.']);
    });

    it('handles text with no sentence-ending punctuation', () => {
      // Single run of text without .!?
      const result = chunkText('just one long string without punctuation', 15);
      expect(result).toEqual([
        'just one long ',
        'string without ',
        'punctuation',
      ]);
    });
  });

  // ─── Over-long sentence hard-split ────────────────────────────────────────

  describe('over-long sentence hard-split', () => {
    it('hard-splits a single sentence longer than maxLength', () => {
      const result = chunkText('abcdefghij', 3);
      expect(result).toEqual(['abc', 'def', 'ghi', 'j']);
    });

    it('preserves all characters including punctuation during hard-split', () => {
      const result = chunkText('Hello world! This is a long sentence that goes on.', 10);
      // The first sentence 'Hello world!' is 12 chars > 10
      // → hard-split into 'Hello worl', 'd!'
      // Wait: let me compute: "Hello world!" is exactly 12 chars
      // Actually: H e l l o   w o r l d ! = 12 chars
      // maxLength=10: chunks are 'Hello worl' (10), 'd!' (2)
      // Then ' This is a long sentence that goes on.' - let's compute full behavior
      expect(result.join('')).toBe('Hello world! This is a long sentence that goes on.');
    });

    it('hard-splits an over-long sentence with exact multiples of maxLength', () => {
      const result = chunkText('123456', 2);
      expect(result).toEqual(['12', '34', '56']);
    });
  });

  // ─── Invariants ───────────────────────────────────────────────────────────

  describe('invariants', () => {
    it('no chunk exceeds maxLength', () => {
      const inputs = [
        { text: 'Hello. World! This is a test.', max: 5 },
        { text: 'Short.', max: 4 },
        { text: 'A longer sentence without any punctuation whatsoever here.', max: 10 },
        { text: 'One. Two. Three. Four. Five.', max: 6 },
        { text: 'abcdefghijklmnopqrstuvwxyz', max: 7 },
        { text: 'Hi there.', max: 100 },
      ];

      for (const { text, max } of inputs) {
        const chunks = chunkText(text, max);
        for (const chunk of chunks) {
          expect(chunk.length).toBeLessThanOrEqual(max);
        }
      }
    });

    it('preserves all original content (chunks.join equals trimmed input)', () => {
      const inputs = [
        'Hello. World!',
        '   leading and trailing whitespace   ',
        'A. B. C. D.',
        'Short',
        'One very long sentence without any punctuation at all so it gets hard split by the algorithm',
        'Mixed. Normal sentences here. But this one is an extremely long sentence that goes on and on without stopping.',
      ];

      for (const text of inputs) {
        const maxes = [5, 10, 20, 50, 100];
        for (const max of maxes) {
          const chunks = chunkText(text, max);
          expect(chunks.join('')).toBe(text.trim());
        }
      }
    });
  });

  // ─── Validation: maxLength ────────────────────────────────────────────────

  describe('maxLength validation', () => {
    it('throws when maxLength is 0', () => {
      expect(() => chunkText('text', 0)).toThrow('maxLength must be a positive number');
    });

    it('throws when maxLength is negative', () => {
      expect(() => chunkText('text', -1)).toThrow('maxLength must be a positive number');
    });

    it('throws when maxLength is NaN', () => {
      expect(() => chunkText('text', NaN)).toThrow('maxLength must be a positive number');
    });

    it('does not throw for positive maxLength', () => {
      expect(() => chunkText('text', 1)).not.toThrow();
      expect(() => chunkText('text', 100)).not.toThrow();
    });
  });

  // ─── Mixed: normal sentences + over-long sentences ────────────────────────

  describe('mixed normal and over-long sentences', () => {
    it('handles a normal sentence followed by an over-long sentence', () => {
      // 'Hi.' (3) fits; ' AVeryLongSentenceIndeed' (23) > maxLength=10
      const result = chunkText('Hi. AVeryLongSentenceIndeed', 10);
      expect(result[0]).toBe('Hi.');
      expect(result[result.length - 1].length).toBeLessThanOrEqual(10);
      expect(result.join('')).toBe('Hi. AVeryLongSentenceIndeed');
    });

    it('handles an over-long sentence followed by a normal sentence', () => {
      const result = chunkText('AVeryLongSentenceIndeed. Hi.', 10);
      expect(result.join('')).toBe('AVeryLongSentenceIndeed. Hi.');
      for (const chunk of result) {
        expect(chunk.length).toBeLessThanOrEqual(10);
      }
    });

    it('handles alternating short and over-long sentences', () => {
      const text = 'A. BBBBBBBBBBBBBBBB. C. DDDDDDDDDDDDDDDD. E.';
      const result = chunkText(text, 6);
      expect(result.join('')).toBe(text);
      for (const chunk of result) {
        expect(chunk.length).toBeLessThanOrEqual(6);
      }
    });
  });
});

